sql:
SELECT AVG(pressure) 
FROM spectra 
WHERE sample_id = 1 AND experiment_id = 0;

SELECT sample_id, wavelength
FROM spectra
WHERE experiment_id = 1;

SELECT s11m
FROM spectra
WHERE spectrum_id = 0;

SELECT DISTINCT spectrum_id
FROM access_logs
WHERE access_date >= DATE('now', '-7 days');

SELECT u.user_name, u.role
FROM users u
WHERE u.user_id IN (SELECT e.lead_researcher FROM experiments e);

SELECT method_id, method_name 
FROM measurement_methods 
WHERE sensitivity > 0.03;

SELECT DISTINCT wavelength 
FROM spectra 
WHERE experiment_id > 2;

SELECT spectrum_id
FROM spectrum_measurement_methods
WHERE method_id = 0;

external_knowledge:
- "ocean waves" metaphorically refers to the spectra;
- "environments soaking in moisture over the threshold of abundant dew" refers to conditions where humidity exceeds 75%;
- "unique signatures" indicates the unique identifiers (spectrum_id) of the spectra;
- "from the longest to the shortest wavelengths" means sorting by wavelength in descending order.
